import java.io.*;
import java.util.*;
import java.util.zip.*;
public class Main {
    static class N{HashMap<Character,N>c=new HashMap<>();boolean e;}
    static class T{
        N r=new N();
        void ins(String w){N x=r;for(char c:w.toCharArray()){x.c.putIfAbsent(c,new N());x=x.c.get(c);}x.e=true;}
        boolean get(String w){N x=r;for(char c:w.toCharArray()){if(!x.c.containsKey(c))return false;x=x.c.get(c);}if(x.e){x.e=false;return true;}return false;}
        boolean sw(String w){N x=r;for(char c:w.toCharArray()){if(!x.c.containsKey(c))return false;x=x.c.get(c);}return true;}
    }
    static char[][]map=new char[5][5];
    static boolean[][]vis=new boolean[5][5];
    static int[]dr={-1,-1,-1,0,1,1,1,0},dc={-1,0,1,1,1,0,-1,-1};
    static T trie=new T();
    static int cnt=0;
    public static void main(String[]a)throws Exception{
        BufferedReader br=new BufferedReader(new InputStreamReader(System.in));
        ins();
        for(int i=0;i<5;i++){StringTokenizer st=new StringTokenizer(br.readLine());for(int j=0;j<5;j++)map[i][j]=st.nextToken().charAt(0);}
        for(int i=0;i<5;i++)for(int j=0;j<5;j++)dfs(""+map[i][j],i,j);
        System.out.println(cnt);
    }
    static void ins()throws Exception{
        String e="";;
        byte[]d=Base64.getDecoder().decode(e);
        Inflater f=new Inflater(true);f.setInput(d);
        ByteArrayOutputStream o=new ByteArrayOutputStream();
        byte[]b=new byte[4096];
        while(!f.finished())o.write(b,0,f.inflate(b));
        f.end();
        ds(o.toByteArray(),new int[]{0},trie.r);
    }
    static void ds(byte[]d,int[]p,N n){
        int h=d[p[0]++]&0xFF;n.e=(h&0x80)!=0;int k=h&0x7F;
        for(int i=0;i<k;i++){char c=(char)(d[p[0]++]&0xFF);N x=new N();n.c.put(c,x);ds(d,p,x);}
    }
    static void dfs(String w,int r,int c){
        if(trie.get(w))cnt++;
        if(!trie.sw(w))return;
        vis[r][c]=true;
        for(int i=0;i<8;i++){int nr=r+dr[i],nc=c+dc[i];if(nr<0||nr>=5||nc<0||nc>=5||vis[nr][nc])continue;dfs(w+map[nr][nc],nr,nc);}
        vis[r][c]=false;
    }
}